void GRouteDbCbk::inDbBTermPreDisconnect(odb::dbBTerm* bterm)
{
  odb::dbNet* db_net = bterm->getNet();
  if (db_net != nullptr && !db_net->isSpecial()) {
    grouter_->addDirtyNet(bterm->getNet());
  }
}

